SELECT

FROM sensitive_data_access_log

    tenant_id = #{query.tenantId}

        AND user_id = #{query.userId}


        AND sensitive_type = #{query.sensitiveType}


        AND resource_type = #{query.resourceType}


        AND resource_id = #{query.resourceId}


        AND access_result = #{query.accessResult}


        AND created_at >= #{query.from}


        AND created_at <= #{query.to}


ORDER BY created_at DESC, id DESC
LIMIT #{limit}
OFFSET #{offset}

SELECT COUNT(1)
FROM sensitive_data_access_log

    tenant_id = #{query.tenantId}

        AND user_id = #{query.userId}


        AND sensitive_type = #{query.sensitiveType}


        AND resource_type = #{query.resourceType}


        AND resource_id = #{query.resourceId}


        AND access_result = #{query.accessResult}


        AND created_at >= #{query.from}


        AND created_at <= #{query.to}
